    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xFB096390F2850331ULL + 0xE3CCF759A89D950CULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xFFCADFE363DD87B5ULL + 0x8B187DFBF660C4FBULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xCF927211C0734419ULL + 0x82A0F1D962814C46ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0x893833544913BCF1ULL + 0xC5140BEF559A4323ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xBAE4E164FC23CA71ULL + 0xCCEB0958BA25C7BDULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0xB3F192C599677BF5ULL + 0xE54F94B2F1667C27ULL);
