            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 7538679055600689463U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterG) ^ 355652867779164756U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 10750788562301193747U), 13U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterA) + 16431766417948870766U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 1701994407164716947U;
            aOrbiterF = RotL64((aOrbiterF * 9332308568570154175U), 5U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 14029915501669281338U;
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 1687908395313120882U;
            aOrbiterE = RotL64((aOrbiterE * 1515227237744577663U), 19U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 15428116748601870689U) + aNonceWordE;
            aOrbiterI = (aOrbiterI ^ aOrbiterJ) ^ 11580681911376528015U;
            aOrbiterI = RotL64((aOrbiterI * 3371934307164006165U), 29U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterF) + 250778546920059947U;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 882530949680500179U;
            aOrbiterG = RotL64((aOrbiterG * 2320592516225326143U), 57U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 13558574829919740670U;
            aOrbiterD = (aOrbiterD ^ aOrbiterE) ^ 9022897801021113531U;
            aOrbiterD = RotL64((aOrbiterD * 14527396161678335199U), 21U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterH) + 7108942615669486887U) + aNonceWordB;
            aOrbiterK = (aOrbiterK ^ aOrbiterB) ^ 13947034057000346940U;
            aOrbiterK = RotL64((aOrbiterK * 10470441302819663755U), 35U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterE) + 10103035120304762381U) + aOrbiterUpdateSaltD[((aIndex + 19U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterA) ^ 11444064494290040272U;
