            //
            aIngress = RotL64(aOrbiterE, 37U) ^ aOrbiterG;
            aIngress = aIngress + (RotL64(aOrbiterF, 39U) ^ aOrbiterC);
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterJ, 35U));
