            //
            aWandererB = aWandererB + (((RotL64(aCross, 13U) + RotL64(aOrbiterF, 27U)) + aOrbiterB) + aNonceWordO);
            aWandererH = aWandererH ^ (((RotL64(aScatter, 34U) + RotL64(aOrbiterF, 44U)) + aOrbiterC) + aWandererUpdateSaltF[((aIndex + 23U)) & S_SALT1]);
            aWandererJ = aWandererJ + (((RotL64(aPrevious, 43U) + aOrbiterE) + RotL64(aOrbiterI, 39U)) + aNonceWordP);
