            //
            aOrbiterH = ((aOrbiterH + aOrbiterA) + 16365990323666697561U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterH) ^ 15245272021784824387U) ^ aNonceWordK;
