            aOrbiterC = RotL64((aOrbiterC * 6970298583731466769U), 13U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 5251151849036557331U;
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 3285711656342546731U;
            aOrbiterE = RotL64((aOrbiterE * 3718421775360078071U), 3U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 11609837795165849619U;
